                            background: 'rgba(255,255,255,0.95)',
                            color: '#333'
                        }}
                    />
                    <button
                        className="btn search-btn"
                        onClick={handleSearch}
                        style={{
                            position: 'absolute',
                            right: '8px',
                            top: '50%',
                            transform: 'translateY(-50%)',
                            background: 'linear-gradient(45deg, #667eea, #764ba2)',
                            border: 'none',
                            borderRadius: '50%',
                            width: '50px',
                            height: '50px',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            cursor: 'pointer',
                            boxShadow: '0 4px 15px rgba(0,0,0,0.2)',
                            transition: 'all 0.3s ease'
                        }}
                        onMouseEnter={(e) => e.target.style.transform = 'translateY(-50%) scale(1.1)'}
                        onMouseLeave={(e) => e.target.style.transform = 'translateY(-50%) scale(1)'}
                    >
                        <SearchIcon size={20} strokeWidth={2.5} color="white" />
                    </button>
                </div>

                {/* Feature Highlights */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '2rem',
                    marginTop: '4rem',
                    maxWidth: '800px',
                    margin: '4rem auto 0'
                }}>
                    <div style={{
                        background: 'rgba(255,255,255,0.1)',
                        padding: '2rem',
                        borderRadius: '20px',
                        backdropFilter: 'blur(10px)',
                        border: '1px solid rgba(255,255,255,0.2)',
                        transform: animated ? 'translateY(0)' : 'translateY(30px)',
                        opacity: animated ? 1 : 0,
                        transition: 'all 0.8s ease-out 0.5s'
                    }}>
                        <Globe size={40} style={{ color: '#ffd700', marginBottom: '1rem' }} />
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '0.5rem' }}>Global Network</h3>
                        <p style={{ opacity: 0.8, fontSize: '0.9rem' }}>Access thousands of unique stays worldwide</p>
                    </div>
                    <div style={{
                        background: 'rgba(255,255,255,0.1)',
                        padding: '2rem',
